diff --git a/src/github.ts b/src/github.ts
index 638d7ce..0c6efc8 100644
--- a/src/github.ts
+++ b/src/github.ts
@@ -23,4 +23,11 @@ export class GitHub {
   async getRepo(owner: string, name: string): Promise<unknown> {
     return this.request(`/repos/${owner}/${name}`);
   }
+
+  async listIssues(owner: string, name: string, page = 1): Promise<unknown> {
+    const res = await fetch(`https://api.github.com/repos/${owner}/${name}/issues?page=${page}`, {
+      headers: { Authorization: `Bearer ${this.token}` },
+    });
+    return res.json();
+  }
 }

